import{_ as d,c as a,o as r,aj as p}from"./chunks/framework.CynFBi0q.js";const b=JSON.parse('{"title":"第2章 像产品经理一样思考 — 四大核心思维","description":"","frontmatter":{},"headers":[],"relativePath":"handbook/ai-product/chapter_2.md","filePath":"handbook/ai-product/chapter_2.md","lastUpdated":1782008855000}'),o={name:"handbook/ai-product/chapter_2.md"};function e(n,t,s,l,i,h){return r(),a("div",null,[...t[0]||(t[0]=[p(`<h1 id="第2章-像产品经理一样思考-—-四大核心思维" tabindex="-1">第2章 像产品经理一样思考 — 四大核心思维 <a class="header-anchor" href="#第2章-像产品经理一样思考-—-四大核心思维" aria-label="Permalink to “第2章 像产品经理一样思考 — 四大核心思维”">​</a></h1><p>做了5年产品经理，我发现一个残酷的真相：80%的产品经理终其职业生涯都在凭直觉做决策。不是他们不想用方法论，而是从来没人教过他们什么是&quot;产品思维&quot;。</p><p>我是怕浪猫，这一章我把产品经理最核心的四大思维——用户思维、逻辑思维、管理思维、商业思维——拆解给你看。这四个能力不是&quot;锦上添花&quot;，而是决定你能走多远的&quot;地基&quot;。</p><h2 id="_2-1-用户思维-精准识别需求" tabindex="-1">2.1 用户思维：精准识别需求 <a class="header-anchor" href="#_2-1-用户思维-精准识别需求" aria-label="Permalink to “2.1 用户思维：精准识别需求”">​</a></h2><h3 id="_2-1-1-什么是用户思维" tabindex="-1">2.1.1 什么是用户思维 <a class="header-anchor" href="#_2-1-1-什么是用户思维" aria-label="Permalink to “2.1.1 什么是用户思维”">​</a></h3><p>用户思维的本质只有一句话：<strong>站在用户的视角看问题，而不是站在自己的视角。</strong></p><p>听起来简单，做起来极难。为什么？因为人天然有&quot;自我中心偏差&quot;——你以为你代表用户，其实你只代表你自己。</p><p>举几个典型的&quot;反用户思维&quot;案例：</p><p>案例一：某电商App的搜索功能。产品经理觉得&quot;智能推荐&quot;很酷，于是在搜索框下面放了一堆推荐词。但用户打开搜索框时，脑子里已经有明确的目标了，推荐词反而增加了干扰。数据证明，去掉推荐词后搜索转化率提升了12%。</p><p>案例二：某社交App的注册流程。产品经理觉得多收集一些用户信息有助于个性化推荐，于是在注册时加了5个必填项。结果注册转化率从68%暴跌到31%。后来把必填项减到2个（手机号+验证码），注册转化率恢复到72%，其余信息在后续使用中渐进式收集。</p><p>案例三：某内容平台的编辑器。产品经理给编辑器加了20种排版工具，觉得功能丰富就是好。但实际使用中，90%的作者只用加粗、标题、图片三种。20个工具栏按钮不仅没增加效率，反而增加了认知负担。</p><blockquote><p>用户思维不是&quot;我觉得用户需要什么&quot;，而是&quot;用户在什么场景下遇到了什么问题&quot;。区分这两者，是产品经理入门的第一道坎。</p></blockquote><h3 id="_2-1-2-如何站在用户视角看问题" tabindex="-1">2.1.2 如何站在用户视角看问题 <a class="header-anchor" href="#_2-1-2-如何站在用户视角看问题" aria-label="Permalink to “2.1.2 如何站在用户视角看问题”">​</a></h3><p>站在用户视角看问题，需要四个步骤：</p><p><strong>第一步：放下自己的身份</strong></p><p>你是产品经理，不代表你是典型用户。你每天用自己做的产品，不代表普通用户也会这样用。放下&quot;我很懂用户&quot;的幻觉，是获得用户思维的第一步。</p><p>具体做法：每次做产品决策前，问自己三个问题——</p><ul><li>我做这个决策的依据是什么？是数据还是直觉？</li><li>如果我不是这个产品的产品经理，我会怎么看待这个功能？</li><li>有没有用户说过他们不需要这个功能？</li></ul><p><strong>第二步：走进用户的使用场景</strong></p><p>用户不是在真空中使用你的产品的。他们在地铁上用、在开会时用、在哄孩子时用。场景不同，需求完全不同。</p><p>举例：同样是点外卖，写字楼白领的场景是&quot;中午12点、时间紧张、想吃口热的&quot;，大学生的场景是&quot;晚上10点、在宿舍、想省钱&quot;。场景不同，推荐策略、排序逻辑、优惠设计都应该不同。</p><p><strong>第三步：听用户说什么，更要看用户做什么</strong></p><p>用户说的和做的往往不一致。用户说&quot;我想要更多功能&quot;，但数据显示他只用三个核心功能。用户说&quot;这个功能很重要&quot;，但使用频率极低。</p><p>这就是著名的&quot;表达偏好&quot;和&quot;显示偏好&quot;的区别。表达偏好是用户嘴上说的，显示偏好是用户实际做的。产品经理要更相信显示偏好。</p><p><strong>第四步：区分&quot;解决方案&quot;和&quot;问题本身&quot;</strong></p><p>经典案例：用户说&quot;我想要一匹更快的马&quot;。如果你只听字面意思，你会去培育更快的马种。但如果你穿透到问题本身，用户要的是&quot;更快的交通工具&quot;——于是你发明了汽车。</p><p>在产品设计中，这种例子比比皆是：</p><table tabindex="0"><thead><tr><th>用户说的（解决方案）</th><th>用户真正的需求（问题）</th></tr></thead><tbody><tr><td>&quot;我想要更大的按钮&quot;</td><td>按钮太难点击，操作效率低</td></tr><tr><td>&quot;我想要更多筛选条件&quot;</td><td>搜索结果不够精准</td></tr><tr><td>&quot;我想要夜间模式&quot;</td><td>晚上使用时屏幕太刺眼</td></tr><tr><td>&quot;我想要离线功能&quot;</td><td>网络不稳定，担心数据丢失</td></tr></tbody></table><blockquote><p>用户的每一句抱怨背后，都藏着一个没有说出口的问题。产品经理的工作，就是从抱怨中挖出问题，从问题中找到方案。</p></blockquote><h3 id="_2-1-3-用户思维在产品决策中的应用" tabindex="-1">2.1.3 用户思维在产品决策中的应用 <a class="header-anchor" href="#_2-1-3-用户思维在产品决策中的应用" aria-label="Permalink to “2.1.3 用户思维在产品决策中的应用”">​</a></h3><p>用户思维不是一种&quot;感觉&quot;，而是一套可以落地的方法论。在产品决策中，用户思维体现在三个层面：</p><p><strong>层面一：功能取舍</strong></p><p>每个产品经理都会面临功能取舍的问题。用户思维帮你判断的标准是：<strong>这个功能解决了多少用户的核心问题？</strong></p><p>判断矩阵：</p><table tabindex="0"><thead><tr><th></th><th>核心用户</th><th>非核心用户</th></tr></thead><tbody><tr><td>核心问题</td><td>必做</td><td>选做</td></tr><tr><td>非核心问题</td><td>选做</td><td>不做</td></tr></tbody></table><p>&quot;必做&quot;的优先级最高，&quot;不做&quot;的果断砍掉，&quot;选做&quot;的根据资源情况决定。</p><p><strong>层面二：交互设计</strong></p><p>交互设计的核心原则：<strong>不要让用户思考。</strong></p><p>用户不应该需要&quot;学习&quot;如何使用你的产品。好的交互设计是&quot;零学习成本&quot;的——用户打开产品就知道怎么用。</p><p>几个具体的原则：</p><ol><li><strong>一致性</strong>：同样的操作在产品各处应该有相同的表现。删除按钮始终在右侧，确认按钮始终在左侧。</li><li><strong>反馈即时性</strong>：用户每一步操作都应该有明确的反馈。点击按钮后要有loading状态，操作完成后要有成功提示。</li><li><strong>可撤销性</strong>：重要的操作应该可以撤销。删除内容后应该有回收站，而不是永久消失。</li><li><strong>渐进式展示</strong>：不要一次性展示所有信息。先展示最重要的，用户需要时再展开细节。</li></ol><p><strong>层面三：优先级判断</strong></p><p>当需求堆积如山时，用户思维帮你排序：</p><ol><li>影响核心用户核心体验的问题，最高优先级</li><li>影响核心用户非核心体验的问题，次高优先级</li><li>影响非核心用户核心体验的问题，中等优先级</li><li>影响非核心用户非核心体验的问题，最低优先级</li></ol><blockquote><p>用户思维不是&quot;用户说什么就做什么&quot;，而是&quot;理解用户真正需要什么，然后给出最优解&quot;。有时候用户需要的不是他要求的那个功能，而是一个完全不同的方案。</p></blockquote><h2 id="_2-2-逻辑思维-学会结构拆解" tabindex="-1">2.2 逻辑思维：学会结构拆解 <a class="header-anchor" href="#_2-2-逻辑思维-学会结构拆解" aria-label="Permalink to “2.2 逻辑思维：学会结构拆解”">​</a></h2><h3 id="_2-2-1-什么是逻辑思维" tabindex="-1">2.2.1 什么是逻辑思维 <a class="header-anchor" href="#_2-2-1-什么是逻辑思维" aria-label="Permalink to “2.2.1 什么是逻辑思维”">​</a></h3><p>逻辑思维的本质是：<strong>把复杂问题拆解成简单问题，然后逐一解决。</strong></p><p>产品经理每天面对的问题都是复杂的：用户留存为什么下降？新功能为什么没达到预期？竞品为什么增长更快？这些问题没有简单的答案，但都可以被拆解成更小的、可回答的子问题。</p><p>逻辑思维不是天生的，是可以训练的。最核心的训练方法是MECE原则。</p><h3 id="_2-2-2-mece-原则与结构化拆解" tabindex="-1">2.2.2 MECE 原则与结构化拆解 <a class="header-anchor" href="#_2-2-2-mece-原则与结构化拆解" aria-label="Permalink to “2.2.2 MECE 原则与结构化拆解”">​</a></h3><p>MECE（Mutually Exclusive, Collectively Exhaustive），中文叫&quot;相互独立，完全穷尽&quot;。意思是：拆解问题时，各子问题之间不能重叠（相互独立），所有子问题加起来要覆盖全部情况（完全穷尽）。</p><p>为什么要MECE？因为非MECE的拆解会导致两个问题：</p><ul><li>子问题重叠 → 重复计算，资源浪费</li><li>子问题遗漏 → 盲区出现，决策失误</li></ul><p><strong>MECE拆解实例：用户留存为什么下降？</strong></p><p>非MECE的拆解：</p><ul><li>新用户留存下降</li><li>老用户留存下降</li><li>中等用户留存下降</li></ul><p>问题：什么是&quot;中等用户&quot;？和新老用户有交叉，不MECE。</p><p>MECE的拆解（按用户生命周期）：</p><ul><li>次日留存下降</li><li>7日留存下降</li><li>30日留存下降</li></ul><p>这三类互不重叠，加在一起覆盖了所有用户留存问题。</p><p>继续拆解&quot;次日留存下降&quot;：</p><ul><li>注册→首次使用流失</li><li>首次使用→核心功能触达流失</li><li>核心功能触达→首次价值体验流失</li></ul><p>每一层都可以继续拆解，直到找到可以行动的切入点。</p><p><strong>MECE拆解的四种常用方法</strong></p><table tabindex="0"><thead><tr><th>方法</th><th>适用场景</th><th>示例</th></tr></thead><tbody><tr><td>按时间拆</td><td>流程类问题</td><td>获客→激活→留存→变现→推荐</td></tr><tr><td>按空间拆</td><td>结构类问题</td><td>华东→华南→华北→西部</td></tr><tr><td>按程度拆</td><td>量化类问题</td><td>高频→中频→低频用户</td></tr><tr><td>按要素拆</td><td>组成类问题</td><td>产品→运营→技术→市场</td></tr></tbody></table><blockquote><p>MECE不是一种技巧，而是一种思维习惯。当你习惯了MECE拆解，你会发现大部分复杂问题都有清晰的解法。</p></blockquote><h3 id="_2-2-3-逻辑思维在需求分析与方案设计中的应用" tabindex="-1">2.2.3 逻辑思维在需求分析与方案设计中的应用 <a class="header-anchor" href="#_2-2-3-逻辑思维在需求分析与方案设计中的应用" aria-label="Permalink to “2.2.3 逻辑思维在需求分析与方案设计中的应用”">​</a></h3><p><strong>需求分析中的逻辑思维</strong></p><p>产品经理分析需求时，最常用的逻辑框架是&quot;问题树&quot;：</p><div class="language- line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>核心问题：如何提升电商平台的GMV？</span></span>
<span class="line"><span>├── 提升流量</span></span>
<span class="line"><span>│   ├── 提升新增用户</span></span>
<span class="line"><span>│   └── 提升回访用户</span></span>
<span class="line"><span>├── 提升转化率</span></span>
<span class="line"><span>│   ├── 提升搜索转化</span></span>
<span class="line"><span>│   ├── 提升详情页转化</span></span>
<span class="line"><span>│   └── 提升下单转化</span></span>
<span class="line"><span>└── 提升客单价</span></span>
<span class="line"><span>    ├── 提升单次购买金额</span></span>
<span class="line"><span>    └── 提升复购频次</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br></div></div><p>每一层都是MECE的，你可以清楚地看到：要提升GMV，有且只有这三条路径。接下来你只需要分析每条路径的提升空间，就能找到最优策略。</p><p><strong>方案设计中的逻辑思维</strong></p><p>设计产品方案时，逻辑思维体现在&quot;边界条件&quot;的考虑上。很多产品方案的失败，不是因为主流程设计得不好，而是因为异常流程没有考虑。</p><p>举例：设计一个支付功能。</p><p>主流程很简单：用户点击支付 → 选择支付方式 → 输入密码 → 支付成功。</p><p>但异常流程呢？</p><table tabindex="0"><thead><tr><th>异常场景</th><th>处理方式</th></tr></thead><tbody><tr><td>网络断开</td><td>提示网络异常，保留订单状态</td></tr><tr><td>支付超时</td><td>查询支付状态，若已扣款则显示成功</td></tr><tr><td>余额不足</td><td>提示余额不足，引导充值或换卡</td></tr><tr><td>重复支付</td><td>幂等处理，防止重复扣款</td></tr><tr><td>部分退款</td><td>记录退款明细，更新订单状态</td></tr></tbody></table><p>产品经理的逻辑思维，就体现在对这些边界条件的穷举和设计上。漏掉一个边界条件，上线后就可能是一个生产事故。</p><blockquote><p>逻辑思维的核心不是&quot;聪明&quot;，而是&quot;不漏&quot;。穷举所有可能性，逐一设计应对方案，这就是产品经理的&quot;缜密&quot;。</p></blockquote><h2 id="_2-3-管理思维-让协作井井有条" tabindex="-1">2.3 管理思维：让协作井井有条 <a class="header-anchor" href="#_2-3-管理思维-让协作井井有条" aria-label="Permalink to “2.3 管理思维：让协作井井有条”">​</a></h2><h3 id="_2-3-1-什么是管理思维" tabindex="-1">2.3.1 什么是管理思维 <a class="header-anchor" href="#_2-3-1-什么是管理思维" aria-label="Permalink to “2.3.1 什么是管理思维”">​</a></h3><p>管理思维的本质是：<strong>通过合理的资源配置和流程设计，让团队高效地达成目标。</strong></p><p>产品经理不是管理者，但需要管理思维。因为产品经理要做的事情，几乎都需要跨团队协作。没有管理思维，你就会变成一个&quot;传话筒&quot;——把需求从运营传给研发，把进度从研发传给运营，但项目推进效率极低。</p><p>管理思维不是&quot;管人&quot;，而是&quot;管事&quot;。核心是三个能力：</p><ol><li><strong>目标管理</strong>：让所有人知道要做什么、做到什么程度</li><li><strong>任务分解</strong>：把大目标拆成小任务，让人人有活干</li><li><strong>进度管控</strong>：跟踪任务执行，发现偏差及时纠正</li></ol><h3 id="_2-3-2-目标管理与任务分解" tabindex="-1">2.3.2 目标管理与任务分解 <a class="header-anchor" href="#_2-3-2-目标管理与任务分解" aria-label="Permalink to “2.3.2 目标管理与任务分解”">​</a></h3><p><strong>目标管理：OKR方法</strong></p><p>OKR（Objectives and Key Results）是产品经理最常用的目标管理方法。</p><p>O（Objective）：你要达成什么目标。要有方向感、有激励性。 KR（Key Results）：你怎么知道目标达成了。要可量化、可验证。</p><p>举例：</p><table tabindex="0"><thead><tr><th>O</th><th>KR</th></tr></thead><tbody><tr><td>提升社区活跃度</td><td>KR1：社区DAU从50万提升到80万</td></tr><tr><td></td><td>KR2：日均发帖量从2万提升到5万</td></tr><tr><td></td><td>KR3：帖子平均互动数从2.1提升到4.0</td></tr></tbody></table><p>好的OKR有三个标准：</p><ul><li>有挑战但可达成（完成70%算及格）</li><li>可量化验证（有明确的数据指标）</li><li>上下对齐（团队OKR支撑公司OKR）</li></ul><p><strong>任务分解：WBS方法</strong></p><p>WBS（Work Breakdown Structure）是把大目标拆成小任务的方法。</p><p>核心原则：</p><ol><li>每个任务必须有明确的交付物</li><li>每个任务必须有明确的负责人</li><li>每个任务的完成时间必须是可预估的</li><li>任务之间的依赖关系必须清晰</li></ol><p>举例：把&quot;上线社区V1&quot;拆解为WBS</p><table tabindex="0"><thead><tr><th>任务</th><th>交付物</th><th>负责人</th><th>预估时间</th><th>依赖</th></tr></thead><tbody><tr><td>需求定义</td><td>PRD文档</td><td>产品经理</td><td>3天</td><td>无</td></tr><tr><td>交互设计</td><td>原型图</td><td>设计师</td><td>3天</td><td>PRD</td></tr><tr><td>视觉设计</td><td>设计稿</td><td>设计师</td><td>4天</td><td>原型</td></tr><tr><td>后端开发</td><td>API接口</td><td>后端工程师</td><td>7天</td><td>PRD</td></tr><tr><td>前端开发</td><td>页面</td><td>前端工程师</td><td>7天</td><td>设计稿+API</td></tr><tr><td>测试</td><td>测试报告</td><td>测试工程师</td><td>3天</td><td>全部开发完成</td></tr><tr><td>上线</td><td>线上产品</td><td>全员</td><td>1天</td><td>测试通过</td></tr></tbody></table><blockquote><p>管理思维不是&quot;当领导&quot;，而是&quot;让事情发生&quot;。目标清晰、任务明确、进度可控，项目自然推进。</p></blockquote><h3 id="_2-3-3-管理思维在项目推进中的应用" tabindex="-1">2.3.3 管理思维在项目推进中的应用 <a class="header-anchor" href="#_2-3-3-管理思维在项目推进中的应用" aria-label="Permalink to “2.3.3 管理思维在项目推进中的应用”">​</a></h3><p><strong>进度管控：关键路径法</strong></p><p>在WBS中，有些任务是可以并行的，有些是有前后依赖的。关键路径就是那条&quot;最长的依赖链&quot;——它决定了项目的最短完成时间。</p><p>上面的例子中，关键路径是：PRD → 原型 → 设计稿 → 前端开发 → 测试 → 上线，总计25天。后端开发可以和前端开发并行，不影响总工期。</p><p>产品经理要重点关注关键路径上的任务。如果关键路径上某个任务延期，整个项目就延期。非关键路径上的任务有一定缓冲空间，可以适当调整。</p><p><strong>风险管理：事前预防优于事后救火</strong></p><table tabindex="0"><thead><tr><th>风险类型</th><th>预防措施</th><th>应急方案</th></tr></thead><tbody><tr><td>需求变更</td><td>需求冻结机制</td><td>评估影响后走变更流程</td></tr><tr><td>技术方案变更</td><td>技术预研</td><td>备选方案</td></tr><tr><td>人员变动</td><td>知识文档化</td><td>交叉培训</td></tr><tr><td>外部依赖</td><td>提前对齐</td><td>降级方案</td></tr><tr><td>数据安全</td><td>安全评审</td><td>应急响应流程</td></tr></tbody></table><h2 id="_2-4-商业思维-让产品创造价值" tabindex="-1">2.4 商业思维：让产品创造价值 <a class="header-anchor" href="#_2-4-商业思维-让产品创造价值" aria-label="Permalink to “2.4 商业思维：让产品创造价值”">​</a></h2><h3 id="_2-4-1-什么是商业思维" tabindex="-1">2.4.1 什么是商业思维 <a class="header-anchor" href="#_2-4-1-什么是商业思维" aria-label="Permalink to “2.4.1 什么是商业思维”">​</a></h3><p>商业思维的本质是：<strong>理解产品的商业逻辑，在用户价值和商业价值之间找到最优平衡。</strong></p><p>产品经理如果只考虑用户体验不考虑商业价值，做出来的产品叫&quot;公益项目&quot;。如果只考虑商业价值不考虑用户体验，做出来的产品叫&quot;割韭菜&quot;。优秀的商业思维，是在两者之间找到可持续的平衡点。</p><p>商业思维的三个层次：</p><p><strong>第一层：理解商业模式</strong></p><p>产品怎么赚钱？这是最基本的商业思维。常见的互联网商业模式：</p><table tabindex="0"><thead><tr><th>模式</th><th>代表产品</th><th>核心逻辑</th></tr></thead><tbody><tr><td>广告</td><td>抖音、百度</td><td>用户免费使用，广告主付费</td></tr><tr><td>电商</td><td>淘宝、京东</td><td>交易抽佣或自营差价</td></tr><tr><td>订阅</td><td>Netflix、Spotify</td><td>用户按月/年付费</td></tr><tr><td>增值服务</td><td>游戏、社交</td><td>基础免费，高级功能收费</td></tr><tr><td>SaaS</td><td>飞书、钉钉</td><td>企业按账号/功能付费</td></tr></tbody></table><p><strong>第二层：理解价值链</strong></p><p>产品在价值链中的位置决定了它的议价能力和盈利空间。</p><p>以电商为例，价值链是：供应商 → 平台 → 物流 → 用户。平台在中间，掌握用户流量，议价能力最强。但如果供应商自建渠道（如品牌官网），平台的议价能力就会下降。</p><p><strong>第三层：理解规模效应</strong></p><p>互联网产品的核心竞争力来自规模效应。用户规模越大，数据越多，算法越准，体验越好，吸引更多用户——这是正向飞轮。</p><blockquote><p>商业思维不是&quot;让产品赚钱&quot;，而是&quot;让产品可持续地创造价值&quot;。赚钱是结果，创造价值是过程。</p></blockquote><h3 id="_2-4-2-商业模式与价值链分析" tabindex="-1">2.4.2 商业模式与价值链分析 <a class="header-anchor" href="#_2-4-2-商业模式与价值链分析" aria-label="Permalink to “2.4.2 商业模式与价值链分析”">​</a></h3><p><strong>商业模式画布</strong></p><p>商业模式画布是分析产品商业逻辑的工具，包含9个要素：</p><table tabindex="0"><thead><tr><th>要素</th><th>说明</th><th>举例（外卖平台）</th></tr></thead><tbody><tr><td>客户细分</td><td>产品服务谁</td><td>白领、学生、家庭</td></tr><tr><td>价值主张</td><td>提供什么价值</td><td>方便、快速、选择多</td></tr><tr><td>渠道通路</td><td>如何触达用户</td><td>App、小程序、广告</td></tr><tr><td>客户关系</td><td>如何维护关系</td><td>会员体系、客服</td></tr><tr><td>收入来源</td><td>如何赚钱</td><td>佣金、广告、配送费</td></tr><tr><td>核心资源</td><td>需要什么资源</td><td>骑手、商家、算法</td></tr><tr><td>关键活动</td><td>需要做什么</td><td>供需匹配、配送调度</td></tr><tr><td>重要合作</td><td>需要谁帮助</td><td>餐厅、支付、地图</td></tr><tr><td>成本结构</td><td>钱花在哪里</td><td>骑手工资、补贴、研发</td></tr></tbody></table><p>通过商业模式画布，你可以一目了然地看清产品的商业逻辑。哪个环节是瓶颈，哪个环节有优化空间，一目了然。</p><p><strong>价值链分析</strong></p><p>价值链分析帮助产品经理理解产品在产业链中的位置，以及利润在不同环节的分配。</p><p>以短视频平台为例：</p><div class="language- line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>内容创作 → 内容分发 → 用户消费 → 商业变现</span></span>
<span class="line"><span>（低成本）  （高价值）   （规模效应）  （核心利润）</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><p>内容创作的成本很低（用户免费上传），内容分发是平台的核心能力（算法推荐），用户消费产生流量规模，商业变现是最终目标（广告+电商+直播打赏）。</p><p>产品经理需要思考：我们产品的价值链中，哪个环节最薄弱？加强这个环节能带来多大的收益？</p><h3 id="_2-4-3-商业思维在产品规划中的应用" tabindex="-1">2.4.3 商业思维在产品规划中的应用 <a class="header-anchor" href="#_2-4-3-商业思维在产品规划中的应用" aria-label="Permalink to “2.4.3 商业思维在产品规划中的应用”">​</a></h3><p>商业思维在产品规划中的应用，主要体现在三个决策上：</p><p><strong>决策一：做不做</strong></p><p>不是所有用户需求都值得做。判断标准：</p><table tabindex="0"><thead><tr><th>维度</th><th>评估</th></tr></thead><tbody><tr><td>用户价值</td><td>解决了多少用户的痛点？</td></tr><tr><td>商业价值</td><td>能带来多少收入或成本节约？</td></tr><tr><td>实现成本</td><td>需要多少研发资源？</td></tr><tr><td>战略价值</td><td>是否支撑长期目标？</td></tr></tbody></table><p>综合打分，高优项目优先，低优项目搁置。</p><p><strong>决策二：怎么做</strong></p><p>同一个需求，有不同的实现方案，成本和收益各不相同。</p><p>举例：提升搜索体验。</p><table tabindex="0"><thead><tr><th>方案</th><th>成本</th><th>收益</th><th>性价比</th></tr></thead><tbody><tr><td>优化排序算法</td><td>高</td><td>高</td><td>中</td></tr><tr><td>增加筛选项</td><td>中</td><td>中</td><td>中</td></tr><tr><td>优化搜索建议</td><td>低</td><td>高</td><td>高</td></tr></tbody></table><p>商业思维帮你选择性价比最高的方案。</p><p><strong>决策三：何时做</strong></p><p>产品有节奏感，不是所有功能都要立刻做。商业思维帮你判断时机：</p><ul><li>市场窗口期：竞品还没做，先发优势明显 → 优先</li><li>用户成熟期：用户需要被教育，太早推出效果差 → 等待</li><li>技术成熟期：依赖的技术还不可靠 → 推迟</li></ul><blockquote><p>商业思维的核心不是&quot;算账&quot;，而是&quot;做选择&quot;。资源永远有限，选择做什么比怎么做更重要。</p></blockquote><p><strong>四大思维总结对比表</strong></p><table tabindex="0"><thead><tr><th>思维</th><th>核心问题</th><th>关键方法</th><th>常见误区</th></tr></thead><tbody><tr><td>用户思维</td><td>用户真正需要什么</td><td>场景还原、显示偏好</td><td>把自己当用户</td></tr><tr><td>逻辑思维</td><td>问题如何拆解</td><td>MECE、问题树、边界条件</td><td>拆解不穷尽</td></tr><tr><td>管理思维</td><td>如何高效推进</td><td>OKR、WBS、关键路径</td><td>只管事不管人</td></tr><tr><td>商业思维</td><td>如何创造价值</td><td>商业模式画布、价值链</td><td>只看短期收入</td></tr></tbody></table><hr><p>本章小结：四大核心思维是产品经理的底层操作系统。用户思维让你看到正确的问题，逻辑思维让你找到正确的路径，管理思维让你高效地推进，商业思维让你做出正确的取舍。四个思维缺一不可，缺了哪个，你的产品决策就会出现系统性的偏差。</p><p>觉得有用？收藏起来，下次直接照抄。</p><p>你现在最缺哪种思维？评论区说说，怕浪猫帮你分析。</p><p>关注怕浪猫，下期我们讲&quot;洞察市场，寻找产品机会&quot;——市场分析怎么做、竞品分析怎么写、如何从市场中发现产品机会，一套方法论讲透。</p><p>系列进度 2/16</p><p><strong>下章预告：</strong> 第3章，怕浪猫带你做市场分析。很多产品经理做竞品分析就是列功能对比表，这远远不够。真正的市场洞察，要看到功能背后的战略意图，看到竞品的选择背后的取舍逻辑。下一章，我教你一套&quot;从市场到机会&quot;的完整方法论。</p>`,157)])])}const q=d(o,[["render",e]]);export{b as __pageData,q as default};
